/**
 * Reads each package under packages/ and writes packages/bundles.js with
 * their file contents inlined as base64 buffers. Run before pkg so the
 * plugin sources are bundled as a script (not assets), avoiding pkg's broken
 * path handling for project directories that contain spaces.
 *
 * The generated module exports:
 *   { 'plugin-name': { version, description, files: { 'filename': Buffer } } }
 */
const fs = require('fs');
const path = require('path');

const PACKAGES_DIR = path.join(__dirname, '..', 'packages');
const OUTPUT = path.join(PACKAGES_DIR, 'bundles.js');
const PLUGIN_FILES = ['package.json', 'index.js'];

const entries = [];

const dirs = fs.readdirSync(PACKAGES_DIR, { withFileTypes: true })
  .filter(e => e.isDirectory())
  .map(e => e.name);

for (const name of dirs) {
  const dir = path.join(PACKAGES_DIR, name);

  let version = '?';
  let description = '';
  try {
    const pkg = JSON.parse(fs.readFileSync(path.join(dir, 'package.json'), 'utf8'));
    version = pkg.version || '?';
    description = pkg.description || '';
  } catch (_) {}

  const files = PLUGIN_FILES.map(filename => {
    const content = fs.readFileSync(path.join(dir, filename));
    return `      ${JSON.stringify(filename)}: Buffer.from(${JSON.stringify(content.toString('base64'))}, 'base64')`;
  });

  entries.push(
    `  ${JSON.stringify(name)}: {\n` +
    `    version: ${JSON.stringify(version)},\n` +
    `    description: ${JSON.stringify(description)},\n` +
    `    files: {\n${files.join(',\n')}\n    }\n  }`
  );
}

const output = [
  '// AUTO-GENERATED by scripts/bundle-packages.js — do not edit manually',
  `// Generated: ${new Date().toISOString()}`,
  'module.exports = {',
  entries.join(',\n'),
  '};',
  '',
].join('\n');

fs.writeFileSync(OUTPUT, output);
console.log(`Bundled ${dirs.length} package(s) into packages/bundles.js: ${dirs.join(', ')}`);
